import { Component, inject, PLATFORM_ID } from '@angular/core';
import { Router } from '@angular/router';
import { FormControl, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { AuthStore, UiStore } from '@store/index';
import { ButtonComponent, CardComponent, IconComponent, InputComponent } from '@core/ui/components';

@Component({
  selector: 'app-login-page',
  imports: [ReactiveFormsModule, ButtonComponent, InputComponent, IconComponent, CardComponent],
  templateUrl: './login.page.html',
  styleUrl: './login.page.css',
})
export class LoginPage {
  readonly authStore = inject(AuthStore);
  readonly uiStore = inject(UiStore);
  readonly router = inject(Router);
  readonly platformId = inject(PLATFORM_ID);

  readonly form = new FormGroup({
    email: new FormControl('', {
      nonNullable: true,
      validators: [Validators.required, Validators.email],
    }),
    password: new FormControl('', {
      nonNullable: true,
      validators: [Validators.required, Validators.minLength(6)],
    }),
  });

  get emailControl() {
    return this.form.controls.email;
  }
  get passwordControl() {
    return this.form.controls.password;
  }

  get emailError(): string {
    const c = this.emailControl;
    if (!c.touched) return '';
    if (c.hasError('required')) return 'El email es requerido';
    if (c.hasError('email')) return 'Formato de email inválido';
    return '';
  }

  get passwordError(): string {
    const c = this.passwordControl;
    if (!c.touched) return '';
    if (c.hasError('required')) return 'La contraseña es requerida';
    if (c.hasError('minlength')) return 'Mínimo 6 caracteres';
    return '';
  }

  async onSubmit() {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    const { email, password } = this.form.getRawValue();
    await this.authStore.loginWithEmail(email, password);

    if (this.authStore.isAuthenticated()) {
      this.uiStore.success(
        `¡Bienvenido, ${this.authStore.currentUser()?.name}!`,
        'Sesión iniciada correctamente.',
      );
      this.router.navigate(['/feed']);
    } else if (this.authStore.error()) {
      this.uiStore.danger('Error al iniciar sesión', this.authStore.error()!);
    }
  }

  async onGoogleLogin() {
    await this.authStore.loginWithGoogle();

    if (this.authStore.isAuthenticated()) {
      this.uiStore.success(
        `¡Bienvenido, ${this.authStore.currentUser()?.name}!`,
        'Sesión iniciada con Google.',
      );
      this.router.navigate(['/feed']);
    }
  }
}

import { CommonModule } from '@angular/common';
import { Component, computed, input, signal } from '@angular/core';
import { Router } from '@angular/router';
import { ClickOutsideDirective } from '@core/directives';
import { ButtonComponent, IconComponent } from '@core/ui/components';

export interface MenuActionItem {
  id: string;
  label: string;
  icon?: string;
  disabled?: boolean;
  url?: string;
  action?: () => void;
  children?: MenuActionItem[];
}

@Component({
  selector: 'app-menu',
  templateUrl: './menu.component.html',
  styleUrl: './menu.component.css',
  imports: [IconComponent, ClickOutsideDirective, CommonModule, ButtonComponent],
})
export class MenuComponent {
  private readonly router = new Router();

  readonly items = input<MenuActionItem[]>([]);
  readonly buttonLabel = input<string>('');
  readonly buttonIcon = input<string | null>(null);
  readonly disabled = input<boolean>(false);

  readonly open = signal(false);
  readonly activePath = signal<string | null>(null);

  readonly mappedItems = computed(() => this.buildParentTree(this.items()));

  toggle(): void {
    if (this.disabled()) return;
    this.open.update((v) => !v);
  }

  close(): void {
    this.open.set(false);
    this.activePath.set(null);
  }

  isOpen(path?: string): boolean {
    if (!path) return false;
    const active = this.activePath();
    if (!active) return false;

    return active === path || active.startsWith(`${path}?`);
  }

  handleItemClick(item: MenuActionItem & { parentTree?: string }): void {
    if (item.disabled) return;

    if (item.children?.length) {
      const path = item.parentTree ?? null;
      const active = this.activePath();

      if (active === path) {
        this.activePath.set(this.getParentPath(path));
        return;
      }

      this.activePath.set(path);
      return;
    }

    if (item.action) {
      item.action();
      this.close();
      return;
    }

    if (item.url) {
      this.router.navigateByUrl(item.url);
      this.close();
    }
  }

  private getParentPath(path: string | null): string | null {
    if (!path) return null;

    const parts = path.split('?');
    parts.pop();

    return parts.length ? parts.join('?') : null;
  }

  private buildParentTree(
    items: MenuActionItem[],
    parentPath: string = '',
  ): Array<MenuActionItem & { parentTree: string }> {
    return items.map((item) => {
      const currentPath = parentPath ? `${parentPath}?${item.id}` : item.id;

      return {
        ...item,
        parentTree: currentPath,
        children: item.children ? this.buildParentTree(item.children, currentPath) : undefined,
      };
    });
  }
}

