import { Component, computed, inject, input, output, signal } from '@angular/core';
import { FormControl, ReactiveFormsModule, Validators } from '@angular/forms';
import { Post, Comment, AuthStore } from '@store/index';
import { ButtonComponent, IconComponent } from '@core/ui/components';
import { MenuComponent, PostComposerComponent } from '@core/molecules';
import { RouterLink } from '@angular/router';
@Component({
  selector: 'app-post-card',

  imports: [
    ReactiveFormsModule,
    ButtonComponent,
    IconComponent,
    MenuComponent,
    PostComposerComponent,
    RouterLink,
  ],
  templateUrl: './post-card.component.html',
  styleUrl: './post-card.component.css',
})
export class PostCardComponent {
  readonly authStore = inject(AuthStore);
  readonly post = input.required<Post>();
  readonly liked = input<boolean>(false);

  readonly isOwner = computed(() => this.post().authorId === this.authStore.currentUser()?.id);
  readonly showComments = input<boolean>(false);
  readonly comments = input<Comment[]>([]);

  readonly onSaveEdit = output<{ postId: string; content: string }>();
  readonly onLike = output<void>();
  readonly onToggleComments = output<void>();
  readonly onComment = output<string>();
  readonly onDelete = output<void>();

  readonly isEditing = signal(false);
  readonly editControl = new FormControl('', {
    nonNullable: true,
    validators: [Validators.required, Validators.minLength(1)],
  });

  readonly seeMoreMenu = computed(() => {
    const user = this.authStore.currentUser();
    const post = this.post();

    if (!user || !post) return [];

    const isOwner = post.authorId === user.id;

    return [
      {
        id: 'edit',
        label: 'Editar',
        icon: 'pencil',
        disabled: !isOwner,
        action: () => this.onEditPost(),
      },
      {
        id: 'delete',
        label: 'Eliminar',
        icon: 'trash-2',
        disabled: !isOwner,
        action: () => this.onDelete.emit(),
      },
    ];
  });

  readonly commentControl = new FormControl('', {
    nonNullable: true,
    validators: [Validators.required, Validators.minLength(1)],
  });

  get timeAgo(): string {
    const diff = Date.now() - this.post().createdAt;
    const mins = Math.floor(diff / 60000);
    const hours = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);
    if (mins < 1) return 'ahora';
    if (mins < 60) return `${mins}m`;
    if (hours < 24) return `${hours}h`;
    return `${days}d`;
  }

  submitComment() {
    if (this.commentControl.invalid) return;
    this.onComment.emit(this.commentControl.value.trim());
    this.commentControl.reset();
  }

  onCommentKeyDown(event: KeyboardEvent) {
    if (event.key === 'Enter' && (event.ctrlKey || event.metaKey)) {
      this.submitComment();
    }
  }

  onEditPost(): void {
    this.editControl.setValue(this.post().content);
    this.isEditing.set(true);
  }

  cancelEdit(): void {
    this.isEditing.set(false);
    this.editControl.reset();
  }

  saveEdit(content: string): void {
    if (this.editControl.invalid) return;

    this.onSaveEdit.emit({
      postId: this.post().id,
      content: content,
    });

    this.isEditing.set(false);
  }
}

import { Component, input, OnInit, output, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ButtonComponent, IconComponent } from '@core/ui/components';

@Component({
  selector: 'app-post-composer',

  imports: [FormsModule, ButtonComponent, IconComponent],
  templateUrl: './post-composer.component.html',
  styleUrl: './post-composer.component.css',
})
export class PostComposerComponent implements OnInit {
  readonly initialContent = input<string | null>(null);
  readonly userName = input<string>('');
  readonly userAvatar = input<string | undefined>(undefined);
  readonly onPost = output<string>();
  readonly onCancel = output<void>();

  readonly content = signal('');
  readonly focused = signal(false);
  readonly maxChars = 280;
  readonly mode = input<'create' | 'edit'>('create');
  readonly onSave = output<string>();

  get charsLeft() {
    return this.maxChars - this.content().length;
  }
  get isOverLimit() {
    return this.charsLeft < 0;
  }
  get canSubmit() {
    return this.content().trim().length > 0 && !this.isOverLimit;
  }
  get charsClass() {
    return this.charsLeft < 20
      ? this.isOverLimit
        ? 'composer-chars-over'
        : 'composer-chars-warn'
      : 'composer-chars';
  }

  ngOnInit() {
    if (this.initialContent()) {
      this.content.set(this.initialContent()!);
      this.focused.set(true);
    }
  }

  onInput(value: string) {
    this.content.set(value);
  }
  onFocus() {
    this.focused.set(true);
  }
  onBlur() {
    this.focused.set(this.content().length > 0);
  }

  cancel() {
    this.content.set('');
    this.focused.set(false);
    this.onCancel.emit();
  }

  submit() {
    if (!this.canSubmit) return;

    const value = this.content().trim();

    if (this.mode() === 'edit') {
      this.onSave.emit(value);
    } else {
      this.onPost.emit(value);
    }

    this.content.set('');
    this.focused.set(false);
  }

  onKeyDown(event: KeyboardEvent) {
    if (event.key === 'Enter' && (event.ctrlKey || event.metaKey)) {
      this.submit();
    }

    if (event.key === 'Escape') {
      this.cancel();
    }
  }
}

