import { Component, inject, computed, signal, PLATFORM_ID, effect } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { FormControl, ReactiveFormsModule, Validators } from '@angular/forms';
import { AuthStore } from '@store/auth/auth.store';
import { PostsStore, Post } from '@store/posts/posts.store';
import { UiStore } from '@store/ui/ui.store';
import { CommentsStore } from '@store/comments/comments.store';
import { ButtonComponent, CardComponent, IconComponent } from '@core/ui/components';
import { PostCardComponent } from '@core/organism/index';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';

@Component({
  selector: 'app-profile-page',

  imports: [ReactiveFormsModule, ButtonComponent, IconComponent, CardComponent, PostCardComponent],
  templateUrl: './profile.page.html',
  styleUrl: './profile.page.css',
})
export class ProfilePage {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private platformId = inject(PLATFORM_ID);

  readonly authStore = inject(AuthStore);
  readonly postsStore = inject(PostsStore);
  readonly commentsStore = inject(CommentsStore);
  readonly uiStore = inject(UiStore);

  readonly editing = signal(false);
  readonly expandedPostId = signal<string | null>(null);
  readonly profileId = toSignal(this.route.paramMap.pipe(map((params) => params.get('id') ?? '')), {
    initialValue: '',
  });
  readonly isOwn = computed(() => this.profileId() === this.authStore.currentUser()?.id);
  readonly profileUser = computed(() => {
    const id = this.profileId();
    const current = this.authStore.currentUser();
    if (current?.id === id) return current;
    const post = this.postsStore.posts().find((p) => p.authorId === id);
    if (!post) return null;
    return {
      id,
      name: post.authorName,
      email: '',
      avatar: post.authorAvatar,
      provider: 'email' as const,
    };
  });

  readonly userPosts = computed(() =>
    this.postsStore.sortedPosts().filter((p) => p.authorId === this.profileId()),
  );

  readonly stats = computed(() => {
    const posts = this.userPosts();
    return {
      totalPosts: posts.length,
      totalLikes: posts.reduce((acc, p) => acc + p.likes.length, 0),
      totalComments: posts.reduce((acc, p) => acc + p.commentCount, 0),
    };
  });

  readonly nameControl = new FormControl('', {
    nonNullable: true,
    validators: [Validators.required, Validators.minLength(2)],
  });

  constructor() {
    effect(() => {
      this.profileId();

      window.scrollTo({
        top: 0,
        behavior: 'smooth',
      });
    });
  }

  startEditing() {
    this.nameControl.setValue(this.profileUser()?.name ?? '');
    this.editing.set(true);
  }

  cancelEditing() {
    this.editing.set(false);
  }

  saveProfile() {
    if (this.nameControl.invalid) return;
    const current = this.authStore.currentUser();
    if (!current) return;

    const updated = { ...current, name: this.nameControl.value.trim() };
    if (isPlatformBrowser(this.platformId)) {
      localStorage.setItem('auth_user', JSON.stringify(updated));
    }

    this.uiStore.success('Perfil actualizado');
    this.editing.set(false);
  }

  onToggleLike(postId: string) {
    const user = this.authStore.currentUser();
    if (!user) return;
    this.postsStore.toggleLike(postId, user.id);
  }

  onToggleComments(postId: string) {
    this.expandedPostId.update((id) => (id === postId ? null : postId));
  }

  onCommentAdded(postId: string, content: string) {
    const user = this.authStore.currentUser();
    if (!user) return;
    this.commentsStore.addComment(postId, content, user);
    this.postsStore.incrementCommentCount(postId);
  }

  onDeletePost(postId: string) {
    const user = this.authStore.currentUser();
    if (!user) return;
    this.postsStore.deletePost(postId, user.id);
    this.uiStore.info('Post eliminado');
  }

  isLiked(post: Post) {
    return post.likes.includes(this.authStore.currentUser()?.id ?? '');
  }

  commentsForPost(postId: string) {
    return this.commentsStore.getCommentsForPost(postId);
  }

  goBack() {
    this.router.navigate(['/feed']);
  }
}

import {
  Component,
  input,
  output,
  signal,
  computed,
  ElementRef,
  HostListener,
} from '@angular/core';
import { FormControl } from '@angular/forms';

export interface SelectOption {
  label: string;
  value: string | number;
  disabled?: boolean;
}

@Component({
  selector: 'ui-select',

  imports: [],
  templateUrl: './select.html',
  styleUrl: './select.css',
  host: { class: 'ignore-host' },
})
export class SelectComponent {
  readonly placeholder = input<string>('Seleccionar...');
  readonly options = input<Array<SelectOption>>([]);
  readonly control = input<FormControl | null>(null);
  readonly multiple = input<boolean>(false);
  readonly onChange = output<string | number | Array<string | number>>();

  readonly disabled = computed<boolean>(() => !!this.control()?.disabled);
  readonly invalid = computed<boolean>(
    () => !!this.control()?.touched && !!this.control()?.invalid,
  );

  uid = Math.random().toString(36).slice(2, 9);
  readonly open = signal(false);
  focusedIndex = signal<number | null>(null);

  private searchBuffer = '';
  private searchTimeout: any = null;

  constructor(private el: ElementRef<HTMLElement>) {}

  @HostListener('document:focusin', ['$event'])
  onDocumentFocusIn(event: FocusEvent) {
    const target = event.target as Node | null;
    if (!target) return;
    if (!this.el.nativeElement.contains(target)) {
      if (this.open()) this.handleCloseClick();
    }
  }

  @HostListener('keydown', ['$event'])
  onHostKeydown(event: KeyboardEvent) {
    if (!this.open()) return;
    if (event.key === 'Tab') {
      this.handleCloseClick();
      return;
    }
    if (event.key === 'Escape') {
      this.handleCloseClick();
      (this.el.nativeElement.querySelector(`#dropdown-button-${this.uid}`) as HTMLElement)?.focus();
      event.preventDefault();
      return;
    }
    if (event.key === 'ArrowDown' || event.key === 'ArrowUp') {
      event.preventDefault();
      this.moveFocus(event.key === 'ArrowDown' ? 1 : -1);
    }
  }

  onMenuKeydown(event: KeyboardEvent) {
    this.onHostKeydown(event);
  }

  moveFocus(direction: 1 | -1) {
    const options = this.options();
    if (!options.length) return;
    let idx = this.focusedIndex();
    if (idx == null) {
      const selectedIdx = options.findIndex((o) => this.isSelected(o));
      idx = selectedIdx !== -1 ? selectedIdx : direction === 1 ? 0 : options.length - 1;
    } else {
      let next = idx;
      do {
        next = (next + direction + options.length) % options.length;
      } while (options[next].disabled && next !== idx);
      idx = next;
    }
    this.focusedIndex.set(idx);
    setTimeout(() => {
      (this.el.nativeElement.querySelectorAll('.dropdown-option')[idx!] as HTMLElement)?.focus();
    });
  }

  handleToggleOpen() {
    this.open.update((v) => !v);
    if (this.open()) {
      this.attachKeyboardSearch();
      const selectedIdx = this.options().findIndex((o) => this.isSelected(o));
      this.focusedIndex.set(this.options().length ? (selectedIdx !== -1 ? selectedIdx : 0) : null);
      setTimeout(() => {
        const idx = this.focusedIndex();
        if (idx != null) {
          (this.el.nativeElement.querySelectorAll('.dropdown-option')[idx] as HTMLElement)?.focus();
        }
      });
    } else {
      this.control()?.markAsTouched();
      this.detachKeyboardSearch();
      this.focusedIndex.set(null);
    }
  }

  handleCloseClick() {
    this.searchBuffer = '';
    this.focusedIndex.set(null);
    this.open.set(false);
    this.control()?.markAsTouched();
    this.detachKeyboardSearch();
  }

  attachKeyboardSearch() {
    window.addEventListener('keydown', this.handleKeySearch);
  }
  detachKeyboardSearch() {
    window.removeEventListener('keydown', this.handleKeySearch);
  }

  private handleKeySearch = (e: KeyboardEvent) => {
    if (!this.open()) return;
    const key = e.key.toLowerCase();
    if (key.length !== 1 || e.ctrlKey || e.metaKey || e.altKey) return;
    this.searchBuffer += key;
    clearTimeout(this.searchTimeout);
    this.searchTimeout = setTimeout(() => (this.searchBuffer = ''), 800);
    const index = this.options().findIndex((opt) =>
      opt.label.toLowerCase().startsWith(this.searchBuffer),
    );
    if (index !== -1) {
      this.focusedIndex.set(index);
      setTimeout(() => {
        document.querySelectorAll('.dropdown-option')[index]?.scrollIntoView({ block: 'nearest' });
      });
    }
  };

  isSelected(item: SelectOption): boolean {
    const ctrl = this.control();
    const val = ctrl?.value;
    if (!ctrl) return false;
    return this.multiple() && Array.isArray(val) ? val.includes(item.value) : val === item.value;
  }

  handleOptionClick(option: SelectOption) {
    if (option.disabled) return;
    const ctrl = this.control();
    if (!ctrl) return;
    const val = ctrl.value;
    if (this.multiple()) {
      const values = Array.isArray(val) ? [...val] : [];
      const newValues = values.includes(option.value)
        ? values.filter((v) => v !== option.value)
        : [...values, option.value];
      ctrl.setValue(newValues);
      this.onChange.emit(newValues);
    } else {
      ctrl.setValue(val !== option.value ? option.value : null);
      this.open.set(false);
      this.onChange.emit(option.value);
    }
    ctrl.markAsDirty();
  }

  get dropdownLabel(): string {
    const ctrl = this.control();
    const val = ctrl?.value;
    const opts = this.options();
    if (!ctrl || val == null || (Array.isArray(val) && val.length === 0)) return this.placeholder();
    if (!this.multiple()) return opts.find((o) => o.value === val)?.label ?? this.placeholder();
    if (Array.isArray(val)) {
      const selected = opts.filter((o) => val.includes(o.value));
      if (!selected.length) return this.placeholder();
      return selected.length === 1 ? selected[0].label : `${selected.length} seleccionados`;
    }
    return this.placeholder();
  }
}

import { CommonModule } from '@angular/common';
import { Component, input } from '@angular/core';
import { ComponentStyles } from '@core/models';

export type SeparatorOrientation = 'horizontal' | 'vertical';
export type SeparatorVariant = 'default' | 'muted' | 'strong';
export type SeparatorSize = 'sm' | 'md' | 'lg';

@Component({
  selector: 'ui-separator',

  imports: [CommonModule],
  templateUrl: './separator.html',
  styleUrl: './separator.css',
  host: { class: 'ignore-host' },
})
export class Separator {
  readonly orientation = input<SeparatorOrientation>('horizontal');
  readonly variant = input<SeparatorVariant>('default');
  readonly size = input<SeparatorSize>('md');
  readonly className = input<string>('');
  readonly styles = input<ComponentStyles>({});
  readonly decorative = input<boolean>(true);

  get classes(): string {
    return [
      'separator',
      `separator-${this.orientation()}`,
      `separator-${this.variant()}`,
      `separator-${this.size()}`,
      this.className(),
    ]
      .filter(Boolean)
      .join(' ');
