  withState<AuthState>(initialState),
  withComputed((store) => ({
    isAuthenticated: computed(() => !!store.user()),
    currentUser: computed(() => store.user()),
  })),
  withMethods((store) => ({
    async loginWithEmail(email: string, password: string): Promise<void> {
      patchState(store, { loading: true, error: null });

      await delay(400); // delay para simular la latencia

      const found = MOCK_USERS.find((u) => u.email === email && u.password === password);

      if (!found) {
        patchState(store, {
          loading: false,
          error: 'Email o contraseña incorrectos',
        });
        return;
      }

      const { password: _, ...user } = found;
      saveToStorage(user);
      patchState(store, { user, loading: false, error: null });
    },

    async loginWithGoogle(): Promise<void> {
      patchState(store, { loading: true, error: null });

      await delay(800);
      const GOOGLE_USER_ID = 'google-user-1';

      const user: AuthUser = {
        id: GOOGLE_USER_ID,
        name: 'Juan Carlos Google',
        email: 'google-user@gmail.com',
        avatar: 'https://api.dicebear.com/9.x/avataaars/svg?seed=google',
        provider: 'google',
      };

      saveToStorage(user);
      patchState(store, { user, loading: false, error: null });
    },

    logout(): void {
      saveToStorage(null);
      patchState(store, { user: null, error: null });
    },
  })),
)

signalStore(
  { providedIn: 'root' },
  withState<CommentsState>(initialState),
  withComputed((store) => ({
    commentsByPost: computed(() => {
      const map = new Map<string, Comment[]>();
      for (const comment of store.comments()) {
        const list = map.get(comment.postId) ?? [];
        map.set(comment.postId, [...list, comment]);
      }
      return map;
    }),
  })),
  withMethods((store) => ({
    getCommentsForPost(postId: string): Comment[] {
      return store
        .comments()
        .filter((c) => c.postId === postId)
        .sort((a, b) => a.createdAt - b.createdAt);
    },

    addComment(postId: string, content: string, author: AuthUser): void {
      const newComment: Comment = {
        id: crypto.randomUUID(),
        postId,
        authorId: author.id,
        authorName: author.name,
        authorAvatar: author.avatar,
        content: content.trim(),
        createdAt: Date.now(),
      };

      const updated = [...store.comments(), newComment];
      saveToStorage(updated);
      patchState(store, { comments: updated });
    },

    deleteComment(commentId: string, userId: string): void {
      const comment = store.comments().find((c) => c.id === commentId);
      if (!comment || comment.authorId !== userId) return;

      const updated = store.comments().filter((c) => c.id !== commentId);
      saveToStorage(updated);
      patchState(store, { comments: updated });
    },
  })),
)

